#[allow(dead_code)] // retained for Step 44 clientSplit methods
/// Extracts path refs from a combined args object, leaving the remaining body.
///
/// Keys are removed in order; missing/non-string keys map to Transport errors.
fn split_path_refs(
    args_json: &str,
    keys: &[&str],
) -> std::result::Result<(Vec<String>, JsonValue), SdkError> {
    let mut map: Map<String, JsonValue> = parse_args_json(args_json)?;
    let mut refs = Vec::with_capacity(keys.len());
    for key in keys {
        let value = map
            .remove(*key)
            .and_then(|v| v.as_str().map(str::to_owned))
            .ok_or_else(|| SdkError::transport(format!("missing {key}"), false))?;
        refs.push(value);
    }
    Ok((refs, JsonValue::Object(map)))
}
